import{_ as u,r as n,o as d,c as p,a as e,b as t,t as i,d as o,w as h,e as l}from"./app-d223f2a5.js";const w={},f={id:"frontmatter-title-관련",tabindex:"-1"},m=e("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),y={class:"table-of-contents"},g=l('<hr><h2 id="project-10-part-4" tabindex="-1"><a class="header-anchor" href="#project-10-part-4" aria-hidden="true">#</a> Project 10, part 4</h2><p>Every new project we work on here introduces new concepts to you in isolation and then again in the context of a real app, with the goal being that showing you the same thing twice in different circumstances helps it sink deeper into your long-term memory.</p><p>But today, with our app finished, it’s time for another important part of the long-term process: a test of what you remember, and some challenges to help push you further. Like it or not, this step <em>matters</em> – as the astronaut John Young once said, “the greatest enemy of progress is the illusion of knowledge.”</p><p>Trust me on this: <em>knowing</em> you understand something is way better than <em>thinking</em> you understand it. This is why I keep drilling the essentials into you: I want you to get so bored with <code>Form</code> that you could almost write this course yourself. I want you to see <code>Codable</code> and know exactly what it means and how it works behind the scenes, and never to think to yourself that it’s somehow magic.</p><p>All these foundations we’re building here are going to last you for years, and it means everything you build on top – everything you learn or create in the future – isn’t built on top of half understanding something you read once, but is instead something you can have real, lasting confidence about.</p><p><strong>Today you should work through the wrap up chapter for project 10, complete its review, then work through all three of its challenges.</strong></p><h3 id="cupcake-corner-wrap-up" tabindex="-1"><a class="header-anchor" href="#cupcake-corner-wrap-up" aria-hidden="true">#</a> Cupcake Corner: Wrap up</h3>',8),k={class:"hint-container details"},_=e("summary",null,"Cupcake Corner: Wrap up",-1),b={href:"https://www.hackingwithswift.com/books/ios-swiftui/cupcake-corner-wrap-up",target:"_blank",rel:"noopener noreferrer"},v=e("p",null,"Hopefully this project has shown you how to take the skills you know – SwiftUI’s forms, pickers, steppers, and navigation – and build them into an app that sends all the user’s data off to a server and processes the response.",-1),C=e("p",null,"You might not realize this yet, but the skills you learned in this project are the most important skills for the vast majority of iOS developers: take user data, send it to a server, and process the response probably accounts for half the non-trivial apps in existence. Yes, what data gets sent and how it’s used to update the UI varies massively, but the concepts are identical.",-1),x=e("h4",{id:"review-what-you-learned",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#review-what-you-learned","aria-hidden":"true"},"#"),t(" Review what you learned")],-1),j=e("p",null,"Anyone can sit through a tutorial, but it takes actual work to remember what was taught. It’s my job to make sure you take as much from these tutorials as possible, so I’ve prepared a short review to help you check your learning.",-1),I={href:"https://www.hackingwithswift.com/review/ios-swiftui/cupcake-corner",target:"_blank",rel:"noopener noreferrer"},T=l('<h4 id="challenge" tabindex="-1"><a class="header-anchor" href="#challenge" aria-hidden="true">#</a> Challenge</h4><p>One of the best ways to learn is to write your own code as often as possible, so here are three ways you should try extending this app to make sure you fully understand what’s going on.</p><ol><li>Our address fields are currently considered valid if they contain anything, even if it’s just only whitespace. Improve the validation to make sure a string of pure whitespace is invalid.</li><li>If our call to <code>placeOrder()</code> fails – for example if there is no internet connection – show an informative alert for the user. To test this, try commenting out the <code>request.httpMethod = &quot;POST&quot;</code> line in your code, which should force the request to fail.</li><li>For a more challenging task, try updating the <code>Order</code> class so it saves data such as the user&#39;s delivery address to <code>UserDefaults</code>. This takes a little thinking, because <code>@AppStorage</code> won&#39;t work here, and you&#39;ll find getters and settings cause problems with <code>Codable</code> support. Can you find a middle ground?</li></ol>',3),O={class:"hint-container info"},S=e("p",{class:"hint-container-title"},"Cupcake Corner: Wrap up - Additional",-1),q={href:"https://www.hackingwithswift.com/review/ios-swiftui/cupcake-corner",target:"_blank",rel:"noopener noreferrer"},L=e("hr",null,null,-1);function A(r,B){const s=n("router-link"),a=n("ExternalLinkIcon"),c=n("TagLinks");return d(),p("div",null,[e("h1",f,[m,t(" "+i(r.$frontmatter.title)+" 관련",1)]),e("blockquote",null,[e("p",null,i(r.$frontmatter.description),1)]),e("nav",y,[e("ul",null,[e("li",null,[o(s,{to:"#project-10-part-4"},{default:h(()=>[t("Project 10, part 4")]),_:1}),e("ul",null,[e("li",null,[o(s,{to:"#cupcake-corner-wrap-up"},{default:h(()=>[t("Cupcake Corner: Wrap up")]),_:1})])])])])]),g,e("details",k,[_,e("p",null,[e("a",b,[t("📎link"),o(a)])]),v,C,x,j,e("p",null,[e("a",I,[t("Click here to review what you learned in this project."),o(a)])]),T]),e("div",O,[S,e("p",null,[e("a",q,[t("Review for Project 10: Cupcake Corner"),o(a)])])]),L,o(c)])}const N=u(w,[["render",A],["__file","52.html.vue"]]);export{N as default};
